function useCounter(target, active) {
  const [val, setVal] = useState(0);
  const raf = useRef(null);
  useEffect(() => {
    if (!active) { setVal(0); return; }
    let start = null;
    const duration = 900;
    const step = (ts) => {
      if (!start) start = ts;
      const p = Math.min((ts - start) / duration, 1);
      const ease = 1 - Math.pow(1 - p, 4);
      setVal(Math.round(ease * target));
      if (p < 1) raf.current = requestAnimationFrame(step);
    };
    raf.current = requestAnimationFrame(step);
    return () => cancelAnimationFrame(raf.current);
  }, [target, active]);
  return val;
}

function MetricCard({ label, value, sub, hero, animate }) {
  const count = useCounter(value, animate);
  return (
    <div style={{
      background: hero
        ? "linear-gradient(145deg, #083d22 0%, #0a5c32 60%, #0e7045 100%)"
        : "white",
      borderRadius: 20,
      padding: hero ? "20px 18px 18px" : "16px 14px",
      gridColumn: hero ? "1 / -1" : "auto",
      border: hero ? "none" : "1.5px solid #e8f5eb",
      boxShadow: hero
        ? "0 10px 36px rgba(10,77,28,0.38)"
        : "0 2px 10px rgba(0,0,0,0.05)",
      textAlign: "center",
      position: "relative",
      overflow: "hidden",
    }}>
      {hero && <>
        <div style={{ position:"absolute", top:-50, right:-50, width:150, height:150, borderRadius:"50%", background:"rgba(255,255,255,0.03)", pointerEvents:"none" }}/>
        <div style={{ position:"absolute", bottom:-30, left:-30, width:100, height:100, borderRadius:"50%", background:"rgba(255,255,255,0.03)", pointerEvents:"none" }}/>
      </>}
      {!hero && <div style={{ position:"absolute", top:0, left:0, right:0, height:3, background:"linear-gradient(90deg,#0a5c32,#15a052)", borderRadius:"20px 20px 0 0" }}/>}
      <div style={{ fontSize:9, fontWeight:700, letterSpacing:"0.12em", textTransform:"uppercase", color: hero ? "rgba(255,255,255,0.5)" : "#94a3b8", marginBottom:6, marginTop: hero ? 0 : 4 }}>
        {label}
      </div>
      <div style={{
        fontFamily:"'Sora',sans-serif", fontWeight:800,
        fontSize: hero ? 36 : 21,
        color: hero ? "white" : "#0a5c32",
        letterSpacing:"-0.03em", lineHeight:1,
      }}>
        {fmtD(count)}
      </div>
      <div style={{ fontSize:10, marginTop:5, color: hero ? "rgba(255,255,255,0.45)" : "#94a3b8", fontWeight:500 }}>{sub}</div>
    </div>
  );
}

