    setErr("");
    const rows = DUREES.map(d => {
      const e = calcEch(mon, d), tot = e * d.mois, cout = tot - mon, pct = e / sal;
      return { ...d, e, tot, cout, pct, reste: sal - e };
    });
    const dn = parseInt(duree);
    const sel = rows.find(r => r.mois === dn) || rows.find(r => r.pct <= 0.33) || rows[rows.length - 1];
    setResults({ rows, sal, mon });
    setSelected(sel);
    setAnimated(false);
